/* BTTag — removable pill label atom.
   Figma nodes 3050-6361 / 3050-6644.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

.bt-tag {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  padding: var(--space-2xs) var(--space-xs);
  border-radius: var(--radius-sm);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  white-space: nowrap;
  color: var(--text-primary);
  cursor: default;
  user-select: none;
}

/* ── Default variant ── */
.bt-tag--default {
  background: var(--bg-subtler);
  border: none;
}
.bt-tag--default:hover {
  background: var(--bg-subtlest);
}

/* ── Outline variant ── */
.bt-tag--outline {
  background: transparent;
  border: 1px solid var(--border-secondary);
}
.bt-tag--outline:hover {
  background: var(--bg-subtle);
}

/* ── Close button ── */
.bt-tag__close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  cursor: pointer;
  color: var(--text-primary);
  background: none;
  border: none;
  padding: 0;
  line-height: 1;
}
.bt-tag__close:hover {
  opacity: 0.7;
}

/* ── Left icon slot ── */
.bt-tag__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

/* ── Tag Group ── */
.bt-tag-group {
  display: flex;
  align-items: center;
}
.bt-tag-group--scroll {
  overflow-x: auto;
  flex-wrap: nowrap;
}
.bt-tag-group--wrap {
  flex-wrap: wrap;
}
.bt-tag-group--gap-default {
  gap: var(--space-xs);
}
.bt-tag-group--gap-loose {
  gap: var(--space-sm);
}

/**
 * Props for {@link BTTag}.
 *
 * @example
 * <BTTag label="Flutter" />
 * <BTTag label="Vue" variant="outline" :onRemove="() => remove('Vue')" />
 */
export interface BTTagProps {
  /** Text label shown inside the tag. */
  label: string;
  /** Visual style. @default 'default' */
  variant?: 'default' | 'outline';
  /** When provided, renders a close × button. Caller removes tag from list. */
  onRemove?: () => void;
}

/**
 * Props for {@link BTTagGroup}.
 */
export interface BTTagGroupProps {
  /** List of tags to display. */
  items: BTTagItem[];
  /** Visual variant applied to all tags. @default 'default' */
  variant?: 'default' | 'outline';
  /** Gap between tags. @default 'default' (4px) */
  spacing?: 'default' | 'loose';
  /** Layout mode. @default 'scroll' */
  type?: 'scroll' | 'wrap';
  /** Called when user clicks close on a tag. Caller must update items. */
  onRemove?: (item: BTTagItem, index: number) => void;
}

export interface BTTagItem {
  /** Display text. */
  label: string;
  /** Optional unique key; falls back to label. */
  id?: string;
}

export * from './BTTag.types';
export { default as BTTag } from './BTTag.vue';
export { default as BTTagGroup } from './BTTagGroup.vue';
